 1→// ── Modals: create modal DOM on demand ───────────────────────
 2→
 3→import { t } from "./i18n.js";
 4→
 5→var root = document.getElementById("modalRoot");
 6→
 7→function createModal(id, titleId, bodyId, closeId) {
 8→	var existing = document.getElementById(id);
 9→	if (existing) return existing;
10→
11→	var backdrop = document.createElement("div");
12→	backdrop.id = id;
13→	backdrop.className = "provider-modal-backdrop hidden";
14→
15→	var modal = document.createElement("div");
16→	modal.className = "provider-modal";
17→
18→	var header = document.createElement("div");
19→	header.className = "provider-modal-header";
20→
21→	var title = document.createElement("span");
22→	title.id = titleId;
23→	title.className = "text-sm font-medium text-[var(--text-strong)]";
24→	header.appendChild(title);
25→
26→	var closeBtn = document.createElement("button");
27→	closeBtn.id = closeId;
28→	closeBtn.className =
29→		"text-[var(--muted)] hover:text-[var(--text)] cursor-pointer bg-transparent border-none text-lg leading-none";
30→	closeBtn.textContent = "\u00D7";
31→	header.appendChild(closeBtn);
32→
33→	modal.appendChild(header);
34→
35→	var body = document.createElement("div");
36→	body.id = bodyId;
37→	body.className = "provider-modal-body";
38→	modal.appendChild(body);
39→
40→	backdrop.appendChild(modal);
41→	root.appendChild(backdrop);
42→	return backdrop;
43→}
44→
