 78→
 79→export function fetchSessions() {
 80→	ensureSessionListScrollBinding();
 81→	if (sessionListPaging.loading) {
 82→		sessionListPendingRefresh = true;
 83→		return;
 84→	}
 85→
 86→	sessionListPaging.loading = true;
 87→	var loadedCount = Array.isArray(S.sessions) ? S.sessions.length : 0;
 88→	var refreshLimit = Math.max(
 89→		SESSION_LIST_PAGE_LIMIT,
 90→		Math.min(
 91→			Number.isInteger(loadedCount) && loadedCount > 0 ? loadedCount : SESSION_LIST_PAGE_LIMIT,
 92→			SESSION_LIST_REFRESH_LIMIT_MAX,
 93→		),
 94→	);
 95→
 96→	void fetchSessionListPage({ limit: refreshLimit })
 97→		.then((page) => {
 98→			var merged = mergeSessionListPage(S.sessions, page.sessions, false);
 99→			applySessionList(merged);
100→			applySessionListPaging(page);
101→		})
102→		.catch(() => {})
103→		.finally(() => {
104→			sessionListPaging.loading = false;
105→			if (sessionListPendingRefresh) {
106→				sessionListPendingRefresh = false;
107→				fetchSessions();
108→				return;
109→			}
110→			maybeLoadMoreSessionsFromScroll();
111→		});
112→}
113→
114→function toValidCursor(value) {
115→	var parsed = Number(value);
116→	if (!Number.isInteger(parsed) || parsed < 0) return null;
117→	return parsed;
118→}
119→
120→function parseSessionListPayload(payload) {
121→	if (Array.isArray(payload)) {
122→		return {
123→			sessions: payload,
124→			hasMore: false,
125→			nextCursor: null,
126→			total: payload.length,
127→		};
128→	}
129→
130→	var list = Array.isArray(payload?.sessions) ? payload.sessions : [];
131→	var nextCursor = toValidCursor(payload?.nextCursor);
132→	var hasMore = payload?.hasMore === true && nextCursor !== null;
133→	var total = Number(payload?.total);
134→	return {
135→		sessions: list,
136→		hasMore: hasMore,
137→		nextCursor: hasMore ? nextCursor : null,
138→		total: Number.isInteger(total) && total >= 0 ? total : null,
139→	};
140→}
141→
142→function mergeSessionListPage(existingSessions, incomingSessions, append) {
143→	var existing = Array.isArray(existingSessions) ? existingSessions : [];
144→	var incoming = Array.isArray(incomingSessions) ? incomingSessions : [];
145→
146→	var oldByKey = {};
147→	for (var old of existing) {
148→		if (!old?.key) continue;
149→		oldByKey[old.key] = old;
150→	}
151→
152→	function withLocalFlags(session) {
153→		if (!(session && session.key)) return session;
154→		var prev = oldByKey[session.key];
155→		if (!prev) return session;
156→		var merged = { ...session };
157→		if (prev._localUnread) merged._localUnread = true;
158→		if (prev._replying) merged._replying = true;
159→		if (prev._activeRunId) merged._activeRunId = prev._activeRunId;
160→		return merged;
161→	}
162→
163→	if (!append) {
164→		return incoming.map((session) => withLocalFlags(session));
165→	}
166→
167→	var result = existing.slice();
168→	var indexByKey = {};
169→	for (var i = 0; i < result.length; i += 1) {
170→		var key = result[i]?.key;
171→		if (!key) continue;
172→		indexByKey[key] = i;
173→	}
174→
175→	for (var session of incoming) {
176→		if (!(session && session.key)) continue;
177→		var next = withLocalFlags(session);
178→		var idx = indexByKey[session.key];
179→		if (Number.isInteger(idx)) {
180→			result[idx] = { ...result[idx], ...next };
181→			continue;
182→		}
183→		indexByKey[session.key] = result.length;
184→		result.push(next);
185→	}
186→
187→	return result;
188→}
189→
190→function applySessionList(sessions) {
191→	// Update session store (source of truth) — version guard
192→	// inside Session.update() prevents stale data from overwriting.
193→	sessionStore.setAll(sessions);
194→	// Dual-write to state.js for backward compat
195→	S.setSessions(sessions);
196→	renderSessionList();
197→	updateChatSessionHeader();
198→}
199→
200→function applySessionListPaging(page) {
201→	sessionListPaging.hasMore = page.hasMore === true && Number.isInteger(page.nextCursor);
202→	sessionListPaging.nextCursor = sessionListPaging.hasMore ? page.nextCursor : null;
203→	sessionListPaging.total = Number.isInteger(page.total) ? page.total : null;
204→}
205→
206→async function fetchSessionListPage(options) {
207→	var opts = options || {};
208→	var query = new URLSearchParams();
209→	if (Number.isInteger(opts.cursor) && opts.cursor >= 0) {
210→		query.set("cursor", String(opts.cursor));
211→	}
212→	if (Number.isInteger(opts.limit) && opts.limit > 0) {
213→		query.set("limit", String(opts.limit));
214→	}
215→
216→	var url = "/api/sessions";
217→	var qs = query.toString();
218→	if (qs) url += `?${qs}`;
219→
220→	var response = await fetch(url, {
221→		headers: { Accept: "application/json" },
222→	});
223→	var payload = null;
224→	try {
225→		payload = await response.json();
226→	} catch {
227→		payload = null;
228→	}
229→	if (!response.ok) {
230→		throw new Error(`Failed to fetch sessions (${response.status})`);
231→	}
232→	return parseSessionListPayload(payload);
233→}
234→
235→function shouldLoadMoreSessions() {
236→	var el = S.$("sessionList");
237→	if (!el) return false;
238→	if (el.clientHeight <= 0) return false;
239→	if (sessionListPaging.loading) return false;
240→	if (!(sessionListPaging.hasMore && Number.isInteger(sessionListPaging.nextCursor))) return false;
241→	var distance = el.scrollHeight - (el.scrollTop + el.clientHeight);
242→	return distance <= SESSION_LIST_SCROLL_THRESHOLD;
243→}
244→
245→async function loadMoreSessionsPage() {
246→	if (!shouldLoadMoreSessions()) return;
247→	sessionListPaging.loading = true;
248→	try {
249→		var page = await fetchSessionListPage({
250→			cursor: sessionListPaging.nextCursor,
251→			limit: SESSION_LIST_PAGE_LIMIT,
252→		});
253→		var merged = mergeSessionListPage(S.sessions, page.sessions, true);
254→		applySessionList(merged);
255→		if (page.sessions.length === 0) {
256→			applySessionListPaging({
257→				hasMore: false,
258→				nextCursor: null,
259→				total: page.total,
260→			});
261→		} else {
262→			applySessionListPaging(page);
263→		}
264→	} catch {
265→		// Keep existing list on transient paging errors.
266→	} finally {
267→		sessionListPaging.loading = false;
268→		if (sessionListPendingRefresh) {
269→			sessionListPendingRefresh = false;
270→			fetchSessions();
271→		} else {
272→			maybeLoadMoreSessionsFromScroll();
273→		}
274→	}
275→}
276→
277→function maybeLoadMoreSessionsFromScroll() {
278→	if (!shouldLoadMoreSessions()) return;
279→	void loadMoreSessionsPage();
280→}
281→
282→function handleSessionListScroll() {
283→	if (sessionListScrollRaf) return;
284→	sessionListScrollRaf = requestAnimationFrame(() => {
285→		sessionListScrollRaf = 0;
286→		maybeLoadMoreSessionsFromScroll();
287→	});
288→}
289→
290→function ensureSessionListScrollBinding() {
291→	var nextEl = S.$("sessionList");
292→	if (sessionListScrollEl === nextEl) return;
293→	if (sessionListScrollEl) {
294→		sessionListScrollEl.removeEventListener("scroll", handleSessionListScroll);
295→	}
296→	sessionListScrollEl = nextEl;
297→	if (!sessionListScrollEl) return;
298→	sessionListScrollEl.addEventListener("scroll", handleSessionListScroll, { passive: true });
299→}
