 67→export function SessionHeader({
 68→	showSelectors = true,
 69→	showName = true,
 70→	showShare = true,
 71→	showFork = true,
 72→	showStop = true,
 73→	showClear = true,
 74→	showDelete = true,
 75→	showArchive = true,
 76→	nameOwnLine = false,
 77→	showRenameButton = false,
 78→	actionButtonClass = "chat-session-btn",
 79→	onBeforeShare = null,
 80→	onBeforeArchive = null,
 81→	onBeforeDelete = null,
 82→} = {}) {
 83→	var session = sessionStore.activeSession.value;
 84→	var sessionDataVersion = session?.dataVersion.value || 0;
 85→	var currentKey = sessionStore.activeSessionKey.value;
 86→	var gonAgentsPayload = parseAgentsListPayload(gon.get("agents"));
 87→	var initialAgentOptions = Array.isArray(gonAgentsPayload?.agents) ? gonAgentsPayload.agents : [];
 88→	var initialDefaultAgentId = typeof gonAgentsPayload?.defaultId === "string" ? gonAgentsPayload.defaultId : "main";
 89→
 90→	var [renaming, setRenaming] = useState(false);
 91→	var [clearing, setClearing] = useState(false);
 92→	var [stopping, setStopping] = useState(false);
 93→	var [switchingAgent, setSwitchingAgent] = useState(false);
 94→	var [agentOptions, setAgentOptions] = useState(initialAgentOptions);
 95→	var [defaultAgentId, setDefaultAgentId] = useState(initialDefaultAgentId);
 96→	var [agentOptionsLoaded, setAgentOptionsLoaded] = useState(initialAgentOptions.length > 0);
 97→	var [nodeOptions, setNodeOptions] = useState([]);
 98→	var [switchingNode, setSwitchingNode] = useState(false);
 99→	var inputRef = useRef(null);
100→
101→	var fullName = session ? session.label || session.key : currentKey;
102→	var displayName = nameOwnLine ? fullName : fullName.length > 20 ? `${fullName.slice(0, 20)}\u2026` : fullName;
103→	var replying = session?.replying.value;
104→	var activeRunId = session?.activeRunId.value || null;
105→
106→	var isMain = currentKey === "main";
107→	var isCron = currentKey.startsWith("cron:");
108→	var canRename = !(isMain || isCron);
109→	var canStop = !isCron && replying;
110→	var canArchive = !!session && isArchivableSession(session);
111→	var showArchivedSessions = sessionStore.showArchivedSessions.value;
112→	var currentAgentId = session?.agent_id || defaultAgentId || "main";
113→	var currentNodeId = session?.node_id || "";
114→
115→	useEffect(() => {
116→		var cancelled = false;
117→		sendRpc("agents.list", {}).then((res) => {
118→			if (cancelled) return;
119→			if (!res?.ok) {
120→				setAgentOptionsLoaded(true);
121→				return;
122→			}
123→			var parsed = parseAgentsListPayload(res.payload);
124→			setDefaultAgentId(parsed.defaultId);
125→			setAgentOptions(parsed.agents);
126→			setAgentOptionsLoaded(true);
127→		});
128→		return () => {
129→			cancelled = true;
130→		};
131→	}, [currentKey]);
132→
133→	// Fetch connected nodes and subscribe to presence updates.
134→	useEffect(() => {
135→		var cancelled = false;
136→		var fetchNodes = () => {
137→			sendRpc("node.list", {}).then((res) => {
138→				if (cancelled || !res?.ok) return;
139→				setNodeOptions(Array.isArray(res.payload) ? res.payload : []);
140→			});
141→		};
142→		fetchNodes();
143→		var unsub = onEvent("presence", () => {
144→			if (!cancelled) fetchNodes();
145→		});
146→		return () => {
147→			cancelled = true;
148→			unsub();
149→		};
150→	}, [currentKey]);
151→
152→	var startRename = useCallback(() => {
153→		if (!canRename) return;
154→		setRenaming(true);
155→		requestAnimationFrame(() => {
156→			if (inputRef.current) {
157→				inputRef.current.value = fullName;
158→				inputRef.current.focus();
159→				inputRef.current.select();
160→			}
161→		});
162→	}, [canRename, fullName]);
163→
164→	var commitRename = useCallback(() => {
165→		var val = inputRef.current?.value.trim() || "";
166→		setRenaming(false);
167→		if (val && val !== fullName) {
168→			sendRpc("sessions.patch", { key: currentKey, label: val }).then((res) => {
169→				if (res?.ok) fetchSessions();
170→			});
171→		}
172→	}, [currentKey, fullName]);
173→
174→	var onKeyDown = useCallback(
175→		(e) => {
176→			if (e.key === "Enter" && !e.isComposing) {
177→				e.preventDefault();
178→				commitRename();
179→			}
180→			if (e.key === "Escape") {
181→				setRenaming(false);
182→			}
183→		},
184→		[commitRename],
185→	);
186→
187→	var onFork = useCallback(() => {
188→		sendRpc("sessions.fork", { key: currentKey }).then((res) => {
189→			if (res?.ok && res.payload?.sessionKey) {
190→				fetchSessions();
191→				switchSession(res.payload.sessionKey);
192→			}
193→		});
194→	}, [currentKey]);
195→
196→	var onDelete = useCallback(() => {
197→		if (typeof onBeforeDelete === "function") {
198→			onBeforeDelete();
199→		}
200→		var currentSession = sessionStore.getByKey(currentKey);
201→		var msgCount = currentSession ? currentSession.messageCount || 0 : 0;
202→		var nextKey = nextSessionKey(currentKey);
203→		var doDelete = () => {
204→			sendRpc("sessions.delete", { key: currentKey }).then((res) => {
205→				if (res && !res.ok && res.error && res.error.indexOf("uncommitted changes") !== -1) {
206→					confirmDialog("Worktree has uncommitted changes. Force delete?").then((yes) => {
207→						if (!yes) return;
208→						sendRpc("sessions.delete", { key: currentKey, force: true }).then(() => {
209→							switchSession(nextKey);
210→							fetchSessions();
211→						});
212→					});
213→					return;
214→				}
215→				switchSession(nextKey);
216→				fetchSessions();
217→			});
218→		};
219→		var isUnmodifiedFork = currentSession && currentSession.forkPoint != null && msgCount <= currentSession.forkPoint;
220→		if (msgCount > 0 && !isUnmodifiedFork) {
221→			confirmDialog("Delete this session?").then((yes) => {
222→				if (yes) doDelete();
223→			});
224→		} else {
225→			doDelete();
226→		}
227→	}, [currentKey, onBeforeDelete, sessionDataVersion]);
228→
229→	var onClear = useCallback(() => {
230→		if (clearing) return;
231→		setClearing(true);
232→		clearActiveSession().finally(() => {
233→			setClearing(false);
234→		});
235→	}, [clearing]);
236→
237→	var onStop = useCallback(() => {
238→		if (stopping) return;
239→		var params = { sessionKey: currentKey };
240→		if (activeRunId) params.runId = activeRunId;
241→		setStopping(true);
242→		sendRpc("chat.abort", params)
243→			.then((res) => {
244→				if (!res?.ok) {
245→					showToast(res?.error?.message || "Failed to stop response", "error");
246→					return;
247→				}
248→				setSessionActiveRunId(currentKey, null);
249→				setSessionReplying(currentKey, false);
250→			})
251→			.finally(() => {
252→				setStopping(false);
253→			});
254→	}, [activeRunId, currentKey, stopping]);
255→
256→	var shareSnapshot = useCallback(
257→		async (visibility) => {
258→			var res = await sendRpc("sessions.share.create", { key: currentKey, visibility: visibility });
259→			if (!(res?.ok && res.payload?.path)) {
260→				showToast(res?.error?.message || "Failed to create share link", "error");
261→				return;
262→			}
263→
264→			var url = buildShareUrl(res.payload);
265→			await copyShareUrl(url, visibility);
266→
267→			if (visibility === "private") {
268→				showToast("Private link includes a key, share it only with trusted people", "success");
269→			}
270→
271→			// Reload the active session so the snapshot cutoff notice appears.
272→			switchSession(currentKey);
