 22→/// Append-only JSONL session storage with file locking.
 23→pub struct SessionStore {
 24→    pub base_dir: PathBuf,
 25→}
 26→
 27→#[must_use]
 28→fn slice_on_char_boundaries(content: &str, start: usize, end: usize) -> &str {
 29→    let bounded_start = content.floor_char_boundary(start.min(content.len()));
 30→    let bounded_end = content.floor_char_boundary(end.min(content.len()));
 31→    if bounded_start >= bounded_end {
 32→        return "";
 33→    }
 34→    &content[bounded_start..bounded_end]
 35→}
