 37→impl SessionStore {
 38→    pub fn new(base_dir: PathBuf) -> Self {
 39→        Self { base_dir }
 40→    }
 41→
 42→    /// Sanitize a session key for use as a filename.
 43→    pub fn key_to_filename(key: &str) -> String {
 44→        key.replace(':', "_")
 45→    }
 46→
 47→    fn path_for(&self, key: &str) -> PathBuf {
 48→        self.base_dir
 49→            .join(format!("{}.jsonl", Self::key_to_filename(key)))
 50→    }
 51→
 52→    /// Directory for session media files (screenshots, audio, etc.).
 53→    fn media_dir_for(&self, key: &str) -> PathBuf {
 54→        self.base_dir.join("media").join(Self::key_to_filename(key))
 55→    }
 56→
 57→    /// Absolute path for a session media file.
 58→    pub fn media_path_for(&self, key: &str, filename: &str) -> PathBuf {
 59→        self.media_dir_for(key).join(filename)
 60→    }
 61→
 62→    /// Save a media file for a session. Returns the relative path from base_dir.
 63→    pub async fn save_media(&self, key: &str, filename: &str, data: &[u8]) -> Result<String> {
 64→        let dir = self.media_dir_for(key);
 65→        let file_path = self.media_path_for(key, filename);
 66→        let data = data.to_vec();
 67→
 68→        tokio::task::spawn_blocking(move || -> Result<()> {
 69→            fs::create_dir_all(&dir)?;
 70→            fs::write(&file_path, &data)?;
 71→            Ok(())
 72→        })
 73→        .await??;
 74→
 75→        let sanitized = Self::key_to_filename(key);
 76→        Ok(format!("media/{sanitized}/{filename}"))
 77→    }
 78→
 79→    /// Read a media file. Returns raw bytes.
 80→    pub async fn read_media(&self, key: &str, filename: &str) -> Result<Vec<u8>> {
 81→        let file_path = self.media_path_for(key, filename);
 82→
 83→        tokio::task::spawn_blocking(move || -> Result<Vec<u8>> {
 84→            let data = fs::read(&file_path)?;
 85→            Ok(data)
 86→        })
 87→        .await?
 88→    }
 89→
 90→    /// Append a message (JSON value) as a single line to the session file.
 91→    pub async fn append(&self, key: &str, message: &serde_json::Value) -> Result<()> {
 92→        let path = self.path_for(key);
 93→        let line = serde_json::to_string(message)?;
 94→
 95→        tokio::task::spawn_blocking(move || -> Result<()> {
 96→            if let Some(parent) = path.parent() {
 97→                fs::create_dir_all(parent)?;
 98→            }
 99→            let file = OpenOptions::new().create(true).append(true).open(&path)?;
100→            let mut lock = RwLock::new(file);
101→            let mut guard = lock
102→                .write()
103→                .map_err(|e| Error::lock_failed(e.to_string()))?;
104→            writeln!(*guard, "{line}")?;
105→            Ok(())
106→        })
107→        .await??;
108→
109→        Ok(())
110→    }
111→
112→    /// Read all messages from a session file.
113→    pub async fn read(&self, key: &str) -> Result<Vec<serde_json::Value>> {
114→        let path = self.path_for(key);
115→
116→        tokio::task::spawn_blocking(move || -> Result<Vec<serde_json::Value>> {
117→            if !path.exists() {
118→                return Ok(vec![]);
119→            }
120→            let file = File::open(&path)?;
121→            let reader = BufReader::new(file);
122→            let mut messages = Vec::new();
123→            for line in reader.lines() {
124→                let line = line?;
125→                let trimmed = line.trim();
126→                if trimmed.is_empty() {
127→                    continue;
128→                }
129→                match serde_json::from_str(trimmed) {
130→                    Ok(val) => messages.push(val),
131→                    Err(e) => {
132→                        tracing::warn!("skipping malformed JSONL line: {e}");
133→                    },
134→                }
135→            }
136→            Ok(messages)
137→        })
138→        .await?
139→    }
140→
141→    /// Read all messages from a session that match a given `run_id`.
142→    pub async fn read_by_run_id(&self, key: &str, run_id: &str) -> Result<Vec<serde_json::Value>> {
143→        let all = self.read(key).await?;
144→        let run_id = run_id.to_string();
145→        Ok(all
146→            .into_iter()
