211→    /// Search all sessions for messages containing `query` (case-insensitive).
212→    /// Returns up to `max_results` hits, at most one per session.
213→    pub async fn search(&self, query: &str, max_results: usize) -> Result<Vec<SearchResult>> {
214→        let base = self.base_dir.clone();
215→        let query = query.to_lowercase();
216→
217→        tokio::task::spawn_blocking(move || {
218→            let mut results = Vec::new();
219→            let entries = fs::read_dir(&base)?;
220→
221→            for entry in entries.flatten() {
222→                if results.len() >= max_results {
223→                    break;
224→                }
225→                let path = entry.path();
226→                let Some(name) = path.file_name().and_then(|n| n.to_str()) else {
227→                    continue;
228→                };
229→                let Some(key_raw) = name.strip_suffix(".jsonl") else {
230→                    continue;
231→                };
232→                let session_key = key_raw.replace('_', ":");
233→
234→                let Ok(file) = File::open(&path) else {
235→                    continue;
236→                };
237→                let reader = BufReader::new(file);
238→                for (idx, line) in reader.lines().enumerate() {
239→                    let Ok(line) = line else {
240→                        continue;
241→                    };
242→                    let trimmed = line.trim();
243→                    if trimmed.is_empty() {
244→                        continue;
245→                    }
246→                    let Ok(val) = serde_json::from_str::<serde_json::Value>(trimmed) else {
247→                        continue;
248→                    };
249→                    let content = val.get("content").and_then(|v| v.as_str()).unwrap_or("");
250→                    if content.to_lowercase().contains(&query) {
251→                        let role = val
252→                            .get("role")
253→                            .and_then(|v| v.as_str())
254→                            .unwrap_or("unknown")
255→                            .to_string();
256→
257→                        // Build a snippet: find the match position and extract context.
258→                        let lower = content.to_lowercase();
259→                        let pos = lower.find(&query).unwrap_or(0);
260→                        let start = pos.saturating_sub(40);
261→                        let end = pos.saturating_add(query.len()).saturating_add(60);
262→                        let snippet = slice_on_char_boundaries(content, start, end).to_string();
263→
264→                        results.push(SearchResult {
265→                            session_key: session_key.clone(),
266→                            snippet,
267→                            role,
268→                            message_index: idx,
269→                        });
270→                        // One hit per session is enough for autocomplete.
271→                        break;
272→                    }
273→                }
274→            }
275→
276→            Ok(results)
277→        })
278→        .await?
279→    }
