281→    /// Replace the entire session history with the given messages.
282→    pub async fn replace_history(&self, key: &str, messages: Vec<serde_json::Value>) -> Result<()> {
283→        let path = self.path_for(key);
284→
285→        tokio::task::spawn_blocking(move || -> Result<()> {
286→            if let Some(parent) = path.parent() {
287→                fs::create_dir_all(parent)?;
288→            }
289→            let file = OpenOptions::new()
290→                .create(true)
291→                .write(true)
292→                .truncate(true)
293→                .open(&path)?;
294→            let mut lock = RwLock::new(file);
295→            let mut guard = lock
296→                .write()
297→                .map_err(|e| Error::lock_failed(e.to_string()))?;
298→            for msg in &messages {
299→                let line = serde_json::to_string(msg)?;
300→                writeln!(*guard, "{line}")?;
301→            }
302→            Ok(())
303→        })
304→        .await??;
305→
306→        Ok(())
307→    }
