309→    /// Read all messages as typed [`PersistedMessage`] values.
310→    ///
311→    /// Lines that fail to deserialize into `PersistedMessage` are skipped
312→    /// (with a warning), matching the behavior of [`read`].
313→    pub async fn read_typed(&self, key: &str) -> Result<Vec<crate::message::PersistedMessage>> {
314→        let path = self.path_for(key);
315→
316→        tokio::task::spawn_blocking(move || -> Result<Vec<crate::message::PersistedMessage>> {
317→            if !path.exists() {
318→                return Ok(vec![]);
319→            }
320→            let file = File::open(&path)?;
321→            let reader = BufReader::new(file);
322→            let mut messages = Vec::new();
323→            for line in reader.lines() {
324→                let line = line?;
325→                let trimmed = line.trim();
326→                if trimmed.is_empty() {
327→                    continue;
328→                }
329→                match serde_json::from_str(trimmed) {
330→                    Ok(msg) => messages.push(msg),
331→                    Err(e) => {
332→                        tracing::warn!("skipping malformed JSONL line (typed): {e}");
333→                    },
334→                }
335→            }
336→            Ok(messages)
337→        })
338→        .await?
339→    }
