414→    /// Count messages in a session file without parsing them.
415→    pub async fn count(&self, key: &str) -> Result<u32> {
416→        let path = self.path_for(key);
417→
418→        tokio::task::spawn_blocking(move || -> Result<u32> {
419→            if !path.exists() {
420→                return Ok(0);
421→            }
422→            let file = File::open(&path)?;
423→            let reader = BufReader::new(file);
424→            let count = reader
425→                .lines()
426→                .map_while(std::result::Result::ok)
427→                .filter(|l| !l.trim().is_empty())
428→                .count();
429→            Ok(count as u32)
430→        })
431→        .await?
432→    }
433→}
