  3→fn default_channel_session_key(target: &moltis_channels::ChannelReplyTarget) -> String {
  4→    match &target.thread_id {
  5→        Some(thread_id) => format!(
  6→            "{}:{}:{}:{}",
  7→            target.channel_type, target.account_id, target.chat_id, thread_id
  8→        ),
  9→        None => format!(
 10→            "{}:{}:{}",
 11→            target.channel_type, target.account_id, target.chat_id
 12→        ),
 13→    }
