 16→async fn is_current_channel_session(
 17→    metadata: &SqliteSessionMetadata,
 18→    entry: &moltis_sessions::metadata::SessionEntry,
 19→) -> bool {
 20→    let Some(binding_json) = entry.channel_binding.as_deref() else {
 21→        return false;
 22→    };
 23→    let Ok(target) = serde_json::from_str::<moltis_channels::ChannelReplyTarget>(binding_json)
 24→    else {
 25→        return false;
 26→    };
 27→
 28→    let active_key = metadata
 29→        .get_active_session(
 30→            target.channel_type.as_str(),
 31→            &target.account_id,
 32→            &target.chat_id,
 33→            target.thread_id.as_deref(),
 34→        )
 35→        .await
 36→        .unwrap_or_else(|| default_channel_session_key(&target));
 37→    active_key == entry.key
 38→}
