 40→async fn is_archivable_entry(
 41→    metadata: &SqliteSessionMetadata,
 42→    entry: &moltis_sessions::metadata::SessionEntry,
 43→) -> bool {
 44→    entry.key != "main" && !is_current_channel_session(metadata, entry).await
 45→}
