139→
140→    pub(super) async fn resolve_agent_id_for_entry(
141→        &self,
142→        entry: &moltis_sessions::metadata::SessionEntry,
143→        patch_if_invalid: bool,
144→    ) -> String {
145→        let fallback = self.default_agent_id().await;
146→        let Some(agent_id) = entry
147→            .agent_id
148→            .as_deref()
149→            .map(str::trim)
150→            .filter(|value| !value.is_empty())
151→        else {
152→            return fallback;
153→        };
154→
155→        if agent_id == "main" {
156→            return "main".to_string();
157→        }
158→
159→        if let Some(ref store) = self.agent_persona_store {
160→            match store.get(agent_id).await {
161→                Ok(Some(_)) => {
162→                    return agent_id.to_string();
163→                },
164→                Ok(None) => {
165→                    warn!(
166→                        session = %entry.key,
167→                        agent_id,
168→                        fallback = %fallback,
169→                        "session references unknown agent, falling back to default"
170→                    );
171→                },
172→                Err(error) => {
173→                    warn!(
174→                        session = %entry.key,
175→                        agent_id,
176→                        fallback = %fallback,
177→                        %error,
178→                        "failed to resolve session agent, falling back to default"
179→                    );
180→                },
181→            }
182→        } else {
183→            return agent_id.to_string();
184→        }
185→
186→        if patch_if_invalid {
187→            let _ = self
188→                .metadata
189→                .set_agent_id(&entry.key, Some(&fallback))
190→                .await;
191→        }
192→        fallback
193→    }
194→
195→    async fn ensure_entry_agent_id(
196→        &self,
197→        key: &str,
198→        inherit_from_key: Option<&str>,
199→    ) -> Option<moltis_sessions::metadata::SessionEntry> {
200→        let entry = self.metadata.get(key).await?;
201→        if entry
202→            .agent_id
203→            .as_deref()
204→            .is_some_and(|id| !id.trim().is_empty())
205→        {
206→            let effective = self.resolve_agent_id_for_entry(&entry, true).await;
207→            if entry.agent_id.as_deref() == Some(effective.as_str()) {
208→                return Some(entry);
209→            }
210→            let mut updated = entry;
211→            updated.agent_id = Some(effective);
212→            return Some(updated);
213→        }
214→
215→        let fallback = if let Some(parent_key) = inherit_from_key {
216→            if let Some(parent) = self.metadata.get(parent_key).await {
217→                self.resolve_agent_id_for_entry(&parent, false).await
218→            } else {
219→                self.default_agent_id().await
220→            }
221→        } else {
222→            self.default_agent_id().await
223→        };
224→
225→        let _ = self.metadata.set_agent_id(key, Some(&fallback)).await;
226→        self.metadata.get(key).await
227→    }
228→}
