276→    async fn list(&self) -> ServiceResult {
277→        let all = self.metadata.list().await;
278→
279→        let mut entries: Vec<Value> = Vec::with_capacity(all.len());
280→        for mut e in all {
281→            let agent_id = self.resolve_agent_id_for_entry(&e, false).await;
282→            // Check if this session is the active one for its channel binding.
283→            let active_channel = is_current_channel_session(&self.metadata, &e).await;
284→
285→            // Backfill preview for sessions that have messages but no preview yet.
286→            if e.preview.is_none()
287→                && e.message_count > 0
288→                && let Ok(history) = self.store.read(&e.key).await
289→            {
290→                let new_preview = extract_preview(&history);
291→                if let Some(ref preview) = new_preview {
292→                    self.metadata.set_preview(&e.key, Some(preview)).await;
293→                    e.preview = new_preview;
294→                }
295→            }
296→
297→            let preview = e
298→                .preview
299→                .as_deref()
300→                .map(|p| truncate_preview(p, SESSION_PREVIEW_MAX_CHARS));
301→
302→            entries.push(serde_json::json!({
303→                "id": e.id,
304→                "key": e.key,
305→                "label": e.label,
306→                "model": e.model,
307→                "createdAt": e.created_at,
308→                "updatedAt": e.updated_at,
309→                "messageCount": e.message_count,
310→                "lastSeenMessageCount": e.last_seen_message_count,
311→                "projectId": e.project_id,
312→                "sandbox_enabled": e.sandbox_enabled,
313→                "sandbox_image": e.sandbox_image,
314→                "worktree_branch": e.worktree_branch,
315→                "channelBinding": e.channel_binding,
316→                "activeChannel": active_channel,
317→                "parentSessionKey": e.parent_session_key,
318→                "forkPoint": e.fork_point,
319→                "mcpDisabled": e.mcp_disabled,
320→                "preview": preview,
321→                "archived": e.archived,
322→                "agent_id": agent_id,
323→                "agentId": agent_id,
324→                "node_id": e.node_id,
325→                "version": e.version,
326→            }));
327→        }
328→        Ok(serde_json::json!(entries))
329→    }
