331→    async fn preview(&self, params: Value) -> ServiceResult {
332→        let key = params
333→            .get("key")
334→            .and_then(|v| v.as_str())
335→            .ok_or_else(|| "missing 'key' parameter".to_string())?;
336→        let limit = params.get("limit").and_then(|v| v.as_u64()).unwrap_or(5) as usize;
337→
338→        let messages = self
339→            .store
340→            .read_last_n(key, limit)
341→            .await
342→            .map_err(ServiceError::message)?;
343→        Ok(serde_json::json!({ "messages": filter_ui_history(messages) }))
344→    }
345→
346→    async fn resolve(&self, params: Value) -> ServiceResult {
347→        let key = params
348→            .get("key")
349→            .and_then(|v| v.as_str())
350→            .ok_or_else(|| "missing 'key' parameter".to_string())?;
351→        let include_history = params
352→            .get("include_history")
353→            .and_then(|v| v.as_bool())
354→            .unwrap_or(true);
355→        let inherit_from_key = params
356→            .get("inherit_agent_from")
357→            .and_then(|v| v.as_str())
358→            .filter(|value| !value.trim().is_empty());
359→
360→        self.metadata
361→            .upsert(key, None)
362→            .await
363→            .map_err(ServiceError::message)?;
364→        let entry = self
365→            .ensure_entry_agent_id(key, inherit_from_key)
366→            .await
367→            .ok_or_else(|| format!("session '{key}' not found after resolve"))?;
368→        if !include_history {
369→            if entry.message_count == 0
370→                && let Some(ref hooks) = self.hook_registry
371→            {
372→                let channel = resolve_hook_channel_binding(key, Some(&entry));
373→                let payload = moltis_common::hooks::HookPayload::SessionStart {
374→                    session_key: key.to_string(),
375→                    channel,
376→                };
377→                if let Err(e) = hooks.dispatch(&payload).await {
378→                    warn!(session = %key, error = %e, "SessionStart hook failed");
379→                }
380→            }
381→
382→            return Ok(serde_json::json!({
383→                "entry": {
384→                    "id": entry.id,
385→                    "key": entry.key,
386→                    "label": entry.label,
387→                    "model": entry.model,
388→                    "createdAt": entry.created_at,
389→                    "updatedAt": entry.updated_at,
390→                    "messageCount": entry.message_count,
391→                    "projectId": entry.project_id,
392→                    "archived": entry.archived,
393→                    "sandbox_enabled": entry.sandbox_enabled,
394→                    "sandbox_image": entry.sandbox_image,
395→                    "worktree_branch": entry.worktree_branch,
396→                    "mcpDisabled": entry.mcp_disabled,
397→                    "agent_id": entry.agent_id,
398→                    "agentId": entry.agent_id,
399→                    "node_id": entry.node_id,
400→                    "version": entry.version,
401→                },
402→                "history": [],
403→                "historyTruncated": false,
404→                "historyDroppedCount": 0,
405→            }));
406→        }
407→
408→        let raw_history = self.store.read(key).await.map_err(ServiceError::message)?;
409→
410→        // Recompute preview from combined messages every time resolve runs,
411→        // so sessions get the latest multi-message preview algorithm.
412→        if !raw_history.is_empty() {
413→            let new_preview = extract_preview(&raw_history);
414→            if new_preview.as_deref() != entry.preview.as_deref() {
415→                self.metadata.set_preview(key, new_preview.as_deref()).await;
416→            }
417→        }
418→
419→        // Dispatch SessionStart hook for newly created sessions (empty history).
420→        if raw_history.is_empty()
421→            && let Some(ref hooks) = self.hook_registry
422→        {
423→            let channel = resolve_hook_channel_binding(key, Some(&entry));
424→            let payload = moltis_common::hooks::HookPayload::SessionStart {
425→                session_key: key.to_string(),
426→                channel,
427→            };
428→            if let Err(e) = hooks.dispatch(&payload).await {
429→                warn!(session = %key, error = %e, "SessionStart hook failed");
430→            }
431→        }
432→
433→        let (history, dropped_count) = trim_ui_history(filter_ui_history(raw_history));
434→
435→        Ok(serde_json::json!({
436→            "entry": {
437→                "id": entry.id,
438→                "key": entry.key,
439→                "label": entry.label,
440→                "model": entry.model,
441→                "createdAt": entry.created_at,
442→                "updatedAt": entry.updated_at,
443→                "messageCount": entry.message_count,
444→                "projectId": entry.project_id,
445→                "archived": entry.archived,
446→                "sandbox_enabled": entry.sandbox_enabled,
447→                "sandbox_image": entry.sandbox_image,
448→                "worktree_branch": entry.worktree_branch,
449→                "mcpDisabled": entry.mcp_disabled,
450→                "agent_id": entry.agent_id,
451→                "agentId": entry.agent_id,
452→                "node_id": entry.node_id,
453→                "version": entry.version,
454→            },
455→            "history": history,
456→            "historyTruncated": dropped_count > 0,
457→            "historyDroppedCount": dropped_count,
458→        }))
459→    }
