461→    async fn patch(&self, params: Value) -> ServiceResult {
462→        let p: PatchParams = parse_params(params)?;
463→        let key = &p.key;
464→
465→        let entry = self
466→            .metadata
467→            .get(key)
468→            .await
469→            .ok_or_else(|| format!("session '{key}' not found"))?;
470→        if p.archived == Some(true) && !is_archivable_entry(&self.metadata, &entry).await {
471→            return Err(ServiceError::message(format!(
472→                "session '{key}' cannot be archived"
473→            )));
474→        }
475→        if p.label.is_some() {
476→            let _ = self.metadata.upsert(key, p.label).await;
477→        }
478→        if p.model.is_some() {
479→            self.metadata.set_model(key, p.model).await;
480→        }
481→        if let Some(archived) = p.archived {
482→            self.metadata.set_archived(key, archived).await;
483→        }
484→        if let Some(project_id_opt) = p.project_id {
485→            let project_id = project_id_opt.filter(|s| !s.is_empty());
486→            self.metadata.set_project_id(key, project_id).await;
487→        }
488→        if let Some(worktree_branch_opt) = p.worktree_branch {
489→            let worktree_branch = worktree_branch_opt.filter(|s| !s.is_empty());
490→            self.metadata
491→                .set_worktree_branch(key, worktree_branch)
492→                .await;
493→        }
494→        if let Some(sandbox_image_opt) = p.sandbox_image {
495→            let sandbox_image = sandbox_image_opt.filter(|s| !s.is_empty());
496→            self.metadata
497→                .set_sandbox_image(key, sandbox_image.clone())
498→                .await;
499→            if let Some(ref router) = self.sandbox_router {
500→                if let Some(ref img) = sandbox_image {
501→                    router.set_image_override(key, img.clone()).await;
502→                } else {
503→                    router.remove_image_override(key).await;
504→                }
505→            }
506→        }
507→        if let Some(mcp_disabled) = p.mcp_disabled {
508→            self.metadata.set_mcp_disabled(key, mcp_disabled).await;
509→        }
510→        if let Some(sandbox_enabled_opt) = p.sandbox_enabled {
511→            let old_sandbox = entry.sandbox_enabled;
512→            self.metadata
513→                .set_sandbox_enabled(key, sandbox_enabled_opt)
514→                .await;
515→            if let Some(ref router) = self.sandbox_router {
516→                if let Some(enabled) = sandbox_enabled_opt {
517→                    router.set_override(key, enabled).await;
518→                } else {
519→                    router.remove_override(key).await;
520→                }
521→            }
522→            // Notify the LLM when sandbox state actually changes.
523→            if old_sandbox != sandbox_enabled_opt {
524→                let notification = if sandbox_enabled_opt == Some(false) {
525→                    "Sandbox has been disabled for this session. The `exec` tool now runs \
526→                     commands directly on the host machine. Previous command outputs in this \
527→                     conversation may have come from a sandboxed Linux container with a \
528→                     different OS, filesystem, and environment."
529→                } else if sandbox_enabled_opt == Some(true) {
530→                    "Sandbox has been enabled for this session. The `exec` tool will now run \
531→                     commands inside a sandboxed container. The container has a different \
532→                     filesystem and environment than the host machine."
533→                } else {
534→                    "Sandbox override has been cleared for this session. The `exec` tool will \
535→                     use the global sandbox setting."
536→                };
537→                let msg = PersistedMessage::system(notification);
538→                if let Err(e) = self.store.append_typed(key, &msg).await {
539→                    warn!(session = key, error = %e, "failed to append sandbox state notification");
540→                }
541→            }
542→        }
543→
544→        let entry = self
545→            .metadata
546→            .get(key)
547→            .await
548→            .ok_or_else(|| format!("session '{key}' not found after update"))?;
549→        Ok(serde_json::json!({
550→            "id": entry.id,
551→            "key": entry.key,
552→            "label": entry.label,
553→            "model": entry.model,
554→            "archived": entry.archived,
555→            "sandbox_enabled": entry.sandbox_enabled,
556→            "sandbox_image": entry.sandbox_image,
557→            "worktree_branch": entry.worktree_branch,
558→            "mcpDisabled": entry.mcp_disabled,
559→            "agent_id": entry.agent_id,
560→            "agentId": entry.agent_id,
561→            "node_id": entry.node_id,
562→            "version": entry.version,
563→        }))
564→    }
