566→    async fn reset(&self, params: Value) -> ServiceResult {
567→        let key = params
568→            .get("key")
569→            .and_then(|v| v.as_str())
570→            .ok_or_else(|| "missing 'key' parameter".to_string())?;
571→
572→        self.store.clear(key).await.map_err(ServiceError::message)?;
573→        self.metadata.touch(key, 0).await;
574→        self.metadata.set_preview(key, None).await;
575→
576→        Ok(serde_json::json!({}))
577→    }
