 79→/// Filter out empty assistant messages from history before sending to the UI.
 80→///
 81→/// Empty assistant messages are persisted in the session JSONL for LLM history
 82→/// coherence (so the model sees a complete user→assistant turn), but they
 83→/// should not be shown in the web UI or sent to channels.
 84→pub(super) fn filter_ui_history(messages: Vec<Value>) -> Vec<Value> {
 85→    messages
 86→        .into_iter()
 87→        .enumerate()
 88→        .filter_map(|(idx, mut msg)| {
 89→            if msg.get("role").and_then(|v| v.as_str()) == Some("assistant") {
 90→                let has_content = msg
 91→                    .get("content")
 92→                    .and_then(|v| v.as_str())
 93→                    .is_some_and(|s| !s.trim().is_empty());
 94→                let has_reasoning = msg
 95→                    .get("reasoning")
 96→                    .and_then(|v| v.as_str())
 97→                    .is_some_and(|s| !s.trim().is_empty());
 98→                let has_audio = msg
 99→                    .get("audio")
100→                    .and_then(|v| v.as_str())
101→                    .is_some_and(|s| !s.trim().is_empty());
102→                let keep = has_content || has_reasoning || has_audio;
103→                if !keep {
104→                    return None;
105→                }
106→            }
107→            if let Some(obj) = msg.as_object_mut() {
108→                obj.insert("historyIndex".to_string(), serde_json::json!(idx));
109→            }
110→            Some(msg)
111→        })
112→        .collect()
113→}
