115→/// Extract text content from a single message Value.
116→pub(super) fn message_text(msg: &Value) -> Option<String> {
117→    let text = if let Some(s) = msg.get("content").and_then(|v| v.as_str()) {
118→        s.to_string()
119→    } else if let Some(blocks) = msg.get("content").and_then(|v| v.as_array()) {
120→        blocks
121→            .iter()
122→            .filter_map(|b| {
123→                if b.get("type").and_then(|v| v.as_str()) == Some("text") {
124→                    b.get("text").and_then(|v| v.as_str())
125→                } else {
126→                    None
127→                }
128→            })
129→            .collect::<Vec<_>>()
130→            .join(" ")
131→    } else {
132→        return None;
133→    };
134→    let trimmed = text.trim();
135→    if trimmed.is_empty() {
136→        None
137→    } else {
138→        Some(trimmed.to_string())
139→    }
140→}
