154→/// Truncate a string to `max` chars, appending "…" if truncated.
155→pub(super) fn truncate_preview(s: &str, max: usize) -> String {
156→    if s.len() <= max {
157→        s.to_string()
158→    } else {
159→        format!("{}…", &s[..s.floor_char_boundary(max)])
160→    }
161→}
