163→/// Build a preview by combining user and assistant messages until we
164→/// have enough text (target ~80 chars). Skips tool_result messages.
165→pub(super) fn extract_preview(history: &[Value]) -> Option<String> {
166→    const TARGET: usize = 80;
167→
168→    let mut combined = String::new();
169→    for msg in history {
170→        let role = msg.get("role").and_then(|v| v.as_str()).unwrap_or("");
171→        if role != "user" && role != "assistant" {
172→            continue;
173→        }
174→        let Some(text) = message_text(msg) else {
175→            continue;
176→        };
177→        if !combined.is_empty() {
178→            combined.push_str(" — ");
179→        }
180→        combined.push_str(&text);
181→        if combined.len() >= TARGET {
182→            break;
183→        }
184→    }
185→    if combined.is_empty() {
186→        return None;
187→    }
188→    Some(truncate_preview(&combined, SESSION_PREVIEW_MAX_CHARS))
189→}
