191→pub(super) fn trim_ui_history(mut history: Vec<Value>) -> (Vec<Value>, usize) {
192→    if history.is_empty() {
193→        return (history, 0);
194→    }
195→
196→    let mut dropped = 0usize;
197→    loop {
198→        let size = serde_json::to_vec(&history).map_or(0, |buf| buf.len());
199→        if size <= UI_HISTORY_MAX_BYTES || history.len() <= UI_HISTORY_MIN_MESSAGES {
200→            break;
201→        }
202→
203→        let removable = history.len().saturating_sub(UI_HISTORY_MIN_MESSAGES);
204→        if removable == 0 {
205→            break;
206→        }
207→
208→        let trim_count = removable.min(UI_HISTORY_TRIM_STEP);
209→        history.drain(0..trim_count);
210→        dropped += trim_count;
211→    }
212→
213→    (history, dropped)
214→}
