256→pub(super) fn audio_mime_type(filename: &str) -> &'static str {
257→    match filename.rsplit('.').next().unwrap_or_default() {
258→        "ogg" | "opus" => "audio/ogg",
259→        "webm" => "audio/webm",
260→        "mp3" => "audio/mpeg",
261→        "wav" => "audio/wav",
262→        "aac" => "audio/aac",
263→        "m4a" => "audio/mp4",
264→        "flac" => "audio/flac",
265→        _ => "application/octet-stream",
266→    }
267→}
