269→pub(super) fn image_mime_type(filename: &str) -> &'static str {
270→    match filename.rsplit('.').next().unwrap_or_default() {
271→        "png" => "image/png",
272→        "jpg" | "jpeg" => "image/jpeg",
273→        "gif" => "image/gif",
274→        "webp" => "image/webp",
275→        "bmp" => "image/bmp",
276→        "svg" | "svgz" => "image/svg+xml",
277→        _ => "application/octet-stream",
278→    }
279→}
