281→pub(super) fn sniff_image_mime(bytes: &[u8], fallback: &str) -> String {
282→    if bytes.len() >= 8 && bytes.starts_with(&[0x89, b'P', b'N', b'G', 0x0D, 0x0A, 0x1A, 0x0A]) {
283→        return "image/png".to_string();
284→    }
285→    if bytes.len() >= 3 && bytes.starts_with(&[0xFF, 0xD8, 0xFF]) {
286→        return "image/jpeg".to_string();
287→    }
288→    if bytes.len() >= 6 && (bytes.starts_with(b"GIF87a") || bytes.starts_with(b"GIF89a")) {
289→        return "image/gif".to_string();
290→    }
291→    if bytes.len() >= 12 && &bytes[0..4] == b"RIFF" && &bytes[8..12] == b"WEBP" {
292→        return "image/webp".to_string();
293→    }
294→    fallback.to_string()
295→}
