302→pub(super) fn parse_base64_image_data_url(data_url: &str) -> Option<(String, Vec<u8>)> {
303→    let (meta, body) = data_url.split_once(',')?;
304→    if !meta.starts_with("data:image/") || !meta.contains(";base64") {
305→        return None;
306→    }
307→    let mime = meta
308→        .trim_start_matches("data:")
309→        .split(';')
310→        .next()
311→        .map(str::trim)
312→        .filter(|value| !value.is_empty())?
313→        .to_string();
314→    let decoded = general_purpose::STANDARD.decode(body.trim()).ok()?;
315→    Some((mime, decoded))
316→}
