334→async fn tool_result_image_for_share(
335→    msg: &Value,
336→    session_key: &str,
337→    store: &SessionStore,
338→) -> Option<SharedImageSet> {
339→    let screenshot = msg
340→        .get("result")
341→        .and_then(|v| v.get("screenshot"))
342→        .and_then(|v| v.as_str())
343→        .map(str::trim)?;
344→    let (full_mime, full_bytes) = if screenshot.starts_with("data:image/") {
345→        parse_base64_image_data_url(screenshot)?
346→    } else {
347→        let filename = media_filename(screenshot)?;
348→        let bytes = store.read_media(session_key, filename).await.ok()?;
349→        (image_mime_type(filename).to_string(), bytes)
350→    };
351→
352→    let full_meta = moltis_media::image_ops::get_image_metadata(&full_bytes).ok()?;
353→    let full_asset = SharedImageAsset {
354→        data_url: build_image_data_url(&full_mime, &full_bytes),
355→        width: full_meta.width,
356→        height: full_meta.height,
357→    };
358→
359→    let needs_preview_resize = full_meta.width > SHARE_PREVIEW_MAX_IMAGE_WIDTH
360→        || full_meta.height > SHARE_PREVIEW_MAX_IMAGE_HEIGHT;
361→    let preview_bytes = if needs_preview_resize {
362→        moltis_media::image_ops::resize_image(
363→            &full_bytes,
364→            SHARE_PREVIEW_MAX_IMAGE_WIDTH,
365→            SHARE_PREVIEW_MAX_IMAGE_HEIGHT,
366→        )
367→        .unwrap_or_else(|_| full_bytes.clone())
368→    } else {
369→        full_bytes.clone()
370→    };
371→    let preview_meta = moltis_media::image_ops::get_image_metadata(&preview_bytes).ok()?;
372→    let preview_mime = sniff_image_mime(&preview_bytes, &full_mime);
373→    let preview_asset = SharedImageAsset {
374→        data_url: build_image_data_url(&preview_mime, &preview_bytes),
375→        width: preview_meta.width,
376→        height: preview_meta.height,
377→    };
378→    let full = if preview_asset.data_url == full_asset.data_url {
379→        None
380→    } else {
381→        Some(full_asset)
382→    };
383→
384→    Some(SharedImageSet {
385→        preview: preview_asset,
386→        full,
387→    })
388→}
