398→pub(super) fn is_assignment_key_byte(byte: u8) -> bool {
399→    byte.is_ascii_alphanumeric() || matches!(byte, b'_' | b'-' | b'"' | b'\'' | b'$')
400→}
401→
402→pub(super) fn is_assignment_value_delimiter(byte: u8) -> bool {
403→    byte.is_ascii_whitespace()
404→        || matches!(byte, b'&' | b',' | b';' | b')' | b']' | b'}' | b'"' | b'\'')
405→}
