407→pub(super) fn normalize_assignment_key(key: &str) -> String {
408→    key.trim()
409→        .trim_matches(|ch| ch == '"' || ch == '\'')
410→        .trim_start_matches('$')
411→        .trim_start_matches('-')
412→        .to_ascii_lowercase()
413→}
414→
415→pub(super) fn is_env_var_key(key: &str) -> bool {
416→    let trimmed = key
417→        .trim()
418→        .trim_matches(|ch| ch == '"' || ch == '\'')
419→        .trim_start_matches('$');
420→    let mut chars = trimmed.chars();
421→    let Some(first) = chars.next() else {
422→        return false;
423→    };
424→    if !(first == '_' || first.is_ascii_uppercase()) {
425→        return false;
426→    }
427→    chars.all(|ch| ch == '_' || ch.is_ascii_uppercase() || ch.is_ascii_digit())
428→}
429→
430→pub(super) fn is_sensitive_assignment_key(key: &str) -> bool {
431→    let normalized = normalize_assignment_key(key);
432→    if normalized.is_empty() {
433→        return false;
434→    }
435→
436→    let compact: String = normalized
437→        .chars()
438→        .filter(|ch| ch.is_ascii_alphanumeric())
439→        .collect();
440→    if compact.is_empty() {
441→        return false;
442→    }
443→
444→    matches!(compact.as_str(), "authorization" | "proxyauthorization")
445→        || compact.ends_with("apikey")
446→        || compact.ends_with("token")
447→        || compact.ends_with("secret")
448→        || compact.ends_with("password")
449→        || compact.ends_with("passwd")
450→}
451→
452→pub(super) fn should_redact_assignment_key(key: &str) -> bool {
453→    is_sensitive_assignment_key(key) || is_env_var_key(key)
454→}
