456→pub(super) fn starts_with_ignore_ascii_case(text: &str, start: usize, pattern: &str) -> bool {
457→    let end = start.saturating_add(pattern.len());
458→    text.get(start..end)
459→        .is_some_and(|value| value.eq_ignore_ascii_case(pattern))
460→}
461→
462→pub(super) fn assignment_key_bounds(text: &str, separator_idx: usize) -> Option<(usize, usize)> {
463→    if separator_idx == 0 || separator_idx >= text.len() {
464→        return None;
465→    }
466→    let bytes = text.as_bytes();
467→    let mut key_end = separator_idx;
468→    while key_end > 0 && bytes[key_end - 1].is_ascii_whitespace() {
469→        key_end -= 1;
470→    }
471→    if key_end == 0 {
472→        return None;
473→    }
474→
475→    let mut key_start = key_end;
476→    while key_start > 0 && is_assignment_key_byte(bytes[key_start - 1]) {
477→        key_start -= 1;
478→    }
479→    (key_start < key_end).then_some((key_start, key_end))
480→}
481→
482→pub(super) fn assignment_value_bounds(
483→    text: &str,
484→    separator_idx: usize,
485→    key: &str,
486→) -> Option<(usize, usize)> {
487→    let bytes = text.as_bytes();
488→    if separator_idx >= bytes.len() {
489→        return None;
490→    }
491→
492→    let mut value_start = separator_idx + 1;
493→    while value_start < bytes.len() && bytes[value_start].is_ascii_whitespace() {
494→        value_start += 1;
495→    }
496→    if value_start >= bytes.len() {
497→        return None;
498→    }
499→
500→    let normalized_key = normalize_assignment_key(key);
501→    let mut quoted = None;
502→    let mut redact_start = value_start;
503→    if matches!(bytes[value_start], b'"' | b'\'') {
504→        quoted = Some(bytes[value_start]);
505→        redact_start = value_start + 1;
506→    }
507→    if redact_start >= bytes.len() {
508→        return None;
509→    }
510→
511→    if matches!(
512→        normalized_key.as_str(),
513→        "authorization" | "proxyauthorization"
514→    ) && starts_with_ignore_ascii_case(text, redact_start, "bearer ")
515→    {
516→        redact_start += "bearer ".len();
517→    }
518→    if redact_start >= bytes.len() {
519→        return None;
520→    }
521→
522→    let mut value_end = redact_start;
523→    if let Some(quote_byte) = quoted {
524→        while value_end < bytes.len() && bytes[value_end] != quote_byte {
525→            value_end += 1;
526→        }
527→    } else {
528→        while value_end < bytes.len() && !is_assignment_value_delimiter(bytes[value_end]) {
529→            value_end += 1;
530→        }
531→    }
532→    (value_end > redact_start).then_some((redact_start, value_end))
533→}
