535→pub(super) fn redact_assignment_values(text: &str) -> String {
536→    let mut redacted = text.to_string();
537→    let mut idx = 0usize;
538→
539→    while idx < redacted.len() {
540→        let next_separator = redacted.as_bytes()[idx..]
541→            .iter()
542→            .position(|byte| matches!(byte, b'=' | b':'))
543→            .map(|offset| idx + offset);
544→        let Some(separator_idx) = next_separator else {
545→            break;
546→        };
547→
548→        let Some((key_start, key_end)) = assignment_key_bounds(&redacted, separator_idx) else {
549→            idx = separator_idx + 1;
550→            continue;
551→        };
552→        let key = redacted[key_start..key_end].trim();
553→        if !should_redact_assignment_key(key) {
554→            idx = separator_idx + 1;
555→            continue;
556→        }
557→
558→        let Some((value_start, value_end)) = assignment_value_bounds(&redacted, separator_idx, key)
559→        else {
560→            idx = separator_idx + 1;
561→            continue;
562→        };
563→        if redacted[value_start..value_end].trim().is_empty()
564→            || &redacted[value_start..value_end] == SHARE_REDACTED_VALUE
565→        {
566→            idx = separator_idx + 1;
567→            continue;
568→        }
569→
570→        redacted.replace_range(value_start..value_end, SHARE_REDACTED_VALUE);
571→        idx = value_start + SHARE_REDACTED_VALUE.len();
572→    }
573→
574→    redacted
575→}
