577→pub(super) fn find_case_insensitive(haystack: &str, needle: &str, from: usize) -> Option<usize> {
578→    if from >= haystack.len() {
579→        return None;
580→    }
581→    let needle_lower = needle.to_ascii_lowercase();
582→    let haystack_lower = haystack[from..].to_ascii_lowercase();
583→    haystack_lower
584→        .find(&needle_lower)
585→        .map(|offset| from + offset)
586→}
