588→pub(super) fn redact_bearer_tokens(text: &str) -> String {
589→    let mut redacted = text.to_string();
590→    let mut idx = 0usize;
591→    let needle = "bearer ";
592→
593→    while let Some(start) = find_case_insensitive(&redacted, needle, idx) {
594→        let token_start = start + needle.len();
595→        if token_start >= redacted.len() {
596→            break;
597→        }
598→        if start > 0 && redacted.as_bytes()[start - 1].is_ascii_alphanumeric() {
599→            idx = token_start;
600→            continue;
601→        }
602→
603→        let bytes = redacted.as_bytes();
604→        let mut token_end = token_start;
605→        while token_end < bytes.len() && !is_assignment_value_delimiter(bytes[token_end]) {
606→            token_end += 1;
607→        }
608→        if token_end <= token_start || &redacted[token_start..token_end] == SHARE_REDACTED_VALUE {
609→            idx = token_end.saturating_add(1);
610→            continue;
611→        }
612→
613→        redacted.replace_range(token_start..token_end, SHARE_REDACTED_VALUE);
614→        idx = token_start + SHARE_REDACTED_VALUE.len();
615→    }
616→
617→    redacted
618→}
