650→pub(super) fn tool_result_text_for_share(msg: &Value) -> Option<String> {
651→    let result = msg.get("result");
652→    let mut sections = Vec::new();
653→
654→    if let Some(label) = result
655→        .and_then(|v| v.get("label"))
656→        .and_then(|v| v.as_str())
657→        .map(str::trim)
658→        .filter(|label| !label.is_empty())
659→    {
660→        sections.push(redact_share_secret_values(label));
661→    }
662→    if let Some(stdout) = result
663→        .and_then(|v| v.get("stdout"))
664→        .and_then(|v| v.as_str())
665→        .map(str::trim)
666→        .filter(|stdout| !stdout.is_empty())
667→    {
668→        sections.push(redact_share_secret_values(stdout));
669→    }
670→    if let Some(stderr) = result
671→        .and_then(|v| v.get("stderr"))
672→        .and_then(|v| v.as_str())
673→        .map(str::trim)
674→        .filter(|stderr| !stderr.is_empty())
675→    {
676→        sections.push(format!("stderr:\n{}", redact_share_secret_values(stderr)));
677→    }
678→    if let Some(error) = msg
679→        .get("error")
680→        .and_then(|v| v.as_str())
681→        .map(str::trim)
682→        .filter(|error| !error.is_empty())
683→    {
684→        sections.push(format!("error: {}", redact_share_secret_values(error)));
685→    }
686→    if let Some(exit_code) = result
687→        .and_then(|v| v.get("exit_code"))
688→        .and_then(|v| {
689→            v.as_i64()
690→                .or_else(|| v.as_u64().and_then(|n| i64::try_from(n).ok()))
691→        })
692→        .filter(|exit_code| *exit_code != 0)
693→    {
694→        sections.push(format!("exit {exit_code}"));
695→    }
696→
697→    let content = sections.join("\n\n");
698→    let trimmed = content.trim();
699→    (!trimmed.is_empty()).then(|| trimmed.to_string())
700→}
