716→        SharedMessageRole::User | SharedMessageRole::Assistant => {
717→            message_text_for_share(msg).unwrap_or_default()
718→        },
719→        SharedMessageRole::System | SharedMessageRole::Notice => String::new(),
720→    };
721→    let reasoning = match role {
