731→        },
732→        SharedMessageRole::ToolResult | SharedMessageRole::System | SharedMessageRole::Notice => {
733→            None
734→        },
735→    };
736→    let image = match role {
737→        SharedMessageRole::ToolResult => tool_result_image_for_share(msg, session_key, store).await,
738→        SharedMessageRole::User
739→        | SharedMessageRole::Assistant
740→        | SharedMessageRole::System
741→        | SharedMessageRole::Notice => None,
742→    };
743→    let map_links = match role {
744→        SharedMessageRole::ToolResult => tool_result_map_links_for_share(msg),
745→        SharedMessageRole::User
746→        | SharedMessageRole::Assistant
747→        | SharedMessageRole::System
748→        | SharedMessageRole::Notice => None,
749→    };
750→    let tool_success = match role {
751→        SharedMessageRole::ToolResult => msg.get("success").and_then(|v| v.as_bool()),
752→        SharedMessageRole::User
753→        | SharedMessageRole::Assistant
754→        | SharedMessageRole::System
755→        | SharedMessageRole::Notice => None,
756→    };
757→    let tool_name = match role {
758→        SharedMessageRole::ToolResult => msg
759→            .get("tool_name")
760→            .and_then(|v| v.as_str())
761→            .map(str::trim)
762→            .filter(|v| !v.is_empty())
763→            .map(ToOwned::to_owned),
764→        SharedMessageRole::User
765→        | SharedMessageRole::Assistant
766→        | SharedMessageRole::System
767→        | SharedMessageRole::Notice => None,
768→    };
769→    let tool_command = match role {
770→        SharedMessageRole::ToolResult => {
771→            if tool_name.as_deref() == Some("exec") {
772→                msg.get("arguments")
773→                    .and_then(|v| v.get("command"))
774→                    .and_then(|v| v.as_str())
775→                    .map(str::trim)
776→                    .filter(|v| !v.is_empty())
777→                    .map(redact_share_secret_values)
778→            } else {
779→                None
780→            }
781→        },
782→        SharedMessageRole::User
783→        | SharedMessageRole::Assistant
784→        | SharedMessageRole::System
785→        | SharedMessageRole::Notice => None,
786→    };
787→
788→    if content.is_empty()
789→        && reasoning.is_none()
790→        && audio_data_url.is_none()
791→        && image.is_none()
792→        && map_links.is_none()
793→    {
794→        return None;
795→    }
796→    let created_at = value_u64(msg, "created_at");
797→    let model = if role == SharedMessageRole::Assistant {
798→        msg.get("model")
799→            .and_then(|v| v.as_str())
800→            .map(ToOwned::to_owned)
801→    } else {
802→        None
803→    };
804→    let provider = if role == SharedMessageRole::Assistant {
805→        msg.get("provider")
806→            .and_then(|v| v.as_str())
807→            .map(ToOwned::to_owned)
808→    } else {
809→        None
810→    };
811→
812→    Some(SharedMessage {
813→        role,
814→        content,
815→        reasoning,
816→        audio_data_url,
817→        image,
818→        image_data_url: None,
819→        map_links,
820→        tool_success,
821→        tool_name,
822→        tool_command,
823→        created_at,
824→        model,
825→        provider,
826→    })
827→}
