110→
111→        let fork_point = params
112→            .get("forkPoint")
113→            .and_then(|v| v.as_u64())
114→            .map(|v| v as usize)
115→            .unwrap_or(msg_count);
116→
117→        if fork_point > msg_count {
118→            return Err(format!("forkPoint {fork_point} exceeds message count {msg_count}").into());
119→        }
