132→            .await
133→            .map_err(ServiceError::message)?;
134→
135→        self.metadata.touch(&new_key, fork_point as u32).await;
136→
137→        // Inherit model, project, mcp_disabled, and agent_id from parent.
138→        if let Some(parent) = self.metadata.get(parent_key).await {
139→            let parent_agent = self.resolve_agent_id_for_entry(&parent, false).await;
