177→            )
178→            .await;
179→
180→        // Re-fetch after all mutations to get the final version.
181→        let final_entry = self
182→            .metadata
183→            .get(&new_key)
184→            .await
185→            .ok_or_else(|| format!("forked session '{new_key}' not found after creation"))?;
186→        Ok(serde_json::json!({
187→            "sessionKey": new_key,
