661→	test("deleting unmodified fork skips confirmation dialog", async ({ page }) => {
662→		const pageErrors = await navigateAndWait(page, "/");
663→		await waitForWsConnected(page);
664→
665→		// Create a parent session, then fork it for a real unmodified fork.
666→		await createSession(page);
667→		await openChatMoreModal(page);
668→		const forkBtn = page.locator('#chatMoreModal button[title="Fork session"]');
669→		await expect(forkBtn).toBeVisible({ timeout: 10_000 });
670→		const parentSessionUrl = page.url();
671→		await forkBtn.click();
672→		await expect.poll(() => page.url(), { timeout: 10_000 }).not.toBe(parentSessionUrl);
673→
674→		const forkSessionUrl = page.url();
675→		await openChatMoreModal(page);
676→		const deleteBtn = page.locator('#chatMoreModal button[title="Delete session"]');
677→		await expect(deleteBtn).toBeVisible({ timeout: 10_000 });
678→		await deleteBtn.click();
679→		await expect(page.locator("#chatMoreModal")).toBeHidden({ timeout: 10_000 });
680→
681→		// The confirmation dialog should NOT be visible.
682→		const confirmModal = page.locator(".provider-modal-backdrop:not(.hidden)").filter({
683→			hasText: "Delete this session?",
684→		});
685→		await expect(confirmModal).toHaveCount(0);
686→
687→		// The session should be deleted immediately (no dialog appeared)
688→		// so we should navigate away from the fork session URL.
689→		// switchSession uses history.replaceState (no navigation event),
690→		// so poll the URL rather than using waitForURL which waits for "load".
691→		await expect.poll(() => page.url(), { timeout: 10_000 }).not.toBe(forkSessionUrl);
692→
693→		expect(pageErrors).toEqual([]);
694→	});
